#include <stdio.h>
#include <inttypes.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long sum = 0, sumSq = 0;
        for (int i = 0; i < N; ++i) {
            long long a; scanf("%lld", &a);
            sum += a;
            sumSq += a * a;
        }
        long long ans = (sum * sum - sumSq) / 2;
        printf("%" PRId64 "\n", ans);
    }
    return 0;
}

